def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            acc = 1.0
            for k in range(1, 15):
                factor = ((np.sin(ratio * k * 3.14) + 1) / 2) * (k ** 1.8)
                if k % 4 == 0:
                    factor *= 1.1
                else:
                    factor *= 0.95
                acc += factor / (k + ratio)
            score = acc * np.log1p(capacity) / (item + 1)
            if int(capacity) % 2 == 0 and int(item) % 3 == 0:
                score *= 0.75
            if score > 20:
                score /= 3
        elif 0.05 <= ratio < 0.25:
            prod = 1.0
            for n in range(2, int(capacity ** 0.5) + 3):
                addition = (ratio * np.exp(-n/10) + n / (n + ratio))
                prod *= addition
                if prod > 1e7:
                    prod = np.log1p(prod) ** 2
                    break
            score = np.sqrt(prod) + ratio * 10
            for x in range(1, 8):
                score += ((np.cos(ratio * x * 3.1415) + 1) / 2) * (x ** 1.3)
            if capacity % 3 == 1:
                score -= 1.2 * ratio
            else:
                score += 0.7 * ratio
        elif 0.25 <= ratio <= 0.55:
            for m in range(1, 9):
                val = ((ratio + m/10) ** (m + 1)) / ((m + 1) ** 1.1)
                score += val * (np.log(m + 2) + 0.3)
            remainder = capacity - item
            if remainder < 4:
                score += 12 + remainder * 0.4
            else:
                score -= remainder * 0.8
            if int(capacity) % 5 == 0:
                score *= 1.15
            if score > 25:
                score /= 4
        elif 0.55 < ratio <= 0.85:
            penalty = 0.0
            diff = ratio - 0.55
            for p in range(1, 15):
                term = (diff ** p) * np.exp(-p / 5) * (p ** 1.8)
                penalty += term
                if penalty > 75:
                    penalty = np.sqrt(penalty) * 5
                    break
            score = penalty * 15
            if capacity < item * 1.02:
                score += 20
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 13 == 0):
                score -= 8
            if score < 0:
                score = abs(score) * 2 + 3
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                pow_term = (diff ** q) * (q ** 2.8) / (q + 0.9)
                penalty_ext += pow_term
                if penalty_ext > 1500:
                    penalty_ext = np.log1p(penalty_ext) * 50
                    break
            score = penalty_ext * 25
            if capacity < item * 1.15:
                score += 25
            if (int(capacity * 6) % 9 == 0) and (int(item * 11) % 6 == 0):
                score -= 10
            for z in range(1, 9):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1800:
                score = 1800
        elif 1.2 < ratio <= 2.0:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 18):
                term = ((diff) ** r) * (r ** 3.3)
                if term > 15000:
                    term = np.log1p(term) * 10
                super_penalty += term
            score = super_penalty * 30
            if capacity < item * 2.2:
                score += 35
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                score -= 12
            for w in range(3, 10):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2500:
                score = 2500
        else:
            ultra_penalty = 0
            diff = ratio - 2.0
            for s in range(1, 25):
                term = ((diff) ** s) * (s ** 4)
                if term > 20000:
                    term = np.sqrt(term) * 2
                ultra_penalty += term
            score = ultra_penalty * 40
            if capacity < item * 3.0:
                score += 40
            if (int(capacity * 20) % 6 == 0) and (int(item * 25) % 9 == 0):
                score -= 15
            for y in range(5, 15):
                score += ((diff / y) % 1) * (y * 4)
            if score < 0:
                score = abs(score) * 0.9 + 7
            if score > 3500:
                score = 3500
        if capacity > 500:
            score /= (np.log1p(capacity) + 1.5)
            if ratio > 1.5:
                score *= 0.85
        elif capacity < 10:
            score *= 2.8
            if ratio < 0.2:
                score *= 1.1
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, median_val, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        extra_bonus = np.sum((finite_priorities < q1) * finite_priorities)
        fill_value = (np.max(finite_priorities) * (10 + top_count) - median_val) + extra_bonus * 0.1
    priorities[np.isinf(priorities)] = fill_value
    median_fill = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_fill
    return priorities
